// File: src/discount.ts
export function applyDiscount(price: number, percent: number): number {
  if (price < 0) throw new Error('Price cannot be negative');
  if (percent < 0 || percent > 100) throw new Error('Invalid percent');
  return +(price * (1 - percent / 100)).toFixed(2);
}
// File: src/__tests__/discount.test.ts
import { describe, it, expect } from 'vitest';
import { applyDiscount } from '../discount.js';
describe('applyDiscount', () => {
  it('applies 10% discount correctly', () => {
    expect(applyDiscount(100, 10)).toBe(90);
  });
  it('returns same price for 0% discount', () => {
    expect(applyDiscount(50, 0)).toBe(50);
  });
  it('handles 100% discount (free)', () => {
    expect(applyDiscount(200, 100)).toBe(0);
  });
  it('throws on negative price', () => {
    expect(() => applyDiscount(-10, 10)).toThrow('negative');
  });
  it('throws on invalid percent', () => {
    expect(() => applyDiscount(50, 110)).toThrow('Invalid');
  });
});
